function Solve([int]$n) {
  $out = @()
  for ($i=1; $i -le $n; $i++) {
    $s = ''
    if ($i % 3 -eq 0) { $s += 'Fizz' }
    if ($i % 5 -eq 0) { $s += 'Buzz' }
    $out += ($(if ($s -eq '') { $i.ToString() } else { $s }))
  }
