snippets.C0646:
# Caso: Validar RUT chileno | Nivel: Intermedio | Categoría: Validación
function Solve([string]$rut) {
  $clean = ($rut -replace '[\.\-\s]', '').ToUpper()
  if ($clean.Length -lt 2) { return $false }

  $body = $clean.Substring(0, $clean.Length - 1)
  $dv = $clean.Substring($clean.Length - 1, 1)

  if ($body -notmatch '^[0-9]+$') { return $false }

  $sum = 0
  $mul = 2
  for ($i = $body.Length - 1; $i -ge 0; $i--) {
    $sum += ([int]$body[$i].ToString()) * $mul
    $mul = if ($mul -eq 7) { 2 } else { $mul + 1 }
  }

  $mod = 11 - ($sum % 11)
  $dvCalc = if ($mod -eq 11) { '0' } elseif ($mod -eq 10) { 'K' } else { $mod.ToString() }
  return ($dv -eq $dvCalc)
}

snippets.C0650:
# C0650 · Leer/Escribir CSV (UTF-8) (Intermedio, IO)
# PowerShell · Import-Csv / Export-Csv
function Solve($input="input.csv", $output="output.csv") {
  $rows = Import-Csv $input
  foreach ($r in $rows) {
    if ($r.Email) { $r.Email = $r.Email.Trim().ToLowerInvariant() }
  }
  $rows | Export-Csv -Path $output -NoTypeInformation -Encoding UTF8
}

