  $items = Invoke-RestMethod -Method Get -Uri "$base/api/items" -TimeoutSec 5
  $created = Invoke-RestMethod -Method Post -Uri "$base/api/items" -TimeoutSec 5 -ContentType "application/json" -Body (@{name="Item";qty=1} | ConvertTo-Json)
  return @{ items=$items; created=$created }
}

