# C0656 · Regex: extraer emails (Básico, Texto)
function Solve($text) {
  $re = [regex]::new("[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}", "IgnoreCase")
  $seen = @{}
  $out = @()
  foreach ($m in $re.Matches($text)) {
    if (-not $seen.ContainsKey($m.Value)) { $seen[$m.Value] = $true; $out += $m.Value }
  }
  return $out
}

