# PowerShell · streaming por línea
function Solve($path="data.ndjson") {
  $count = 0
  Get-Content $path | ForEach-Object {
    $line = $_.Trim()
    if ($line) {
      try { $null = $line | ConvertFrom-Json; $count++ } catch {}
    }
  }
  return $count
}

