# C0680 · Uso de teclado (keydown/atajos) (Intermedio, UI/Entrada)
# PowerShell: ReadKey
function Solve() {
  Write-Host "Presiona WASD (q para salir)."
  while ($true) {
    $k = $Host.UI.RawUI.ReadKey("NoEcho,IncludeKeyDown")
    $ch = $k.Character.ToString().ToLowerInvariant()
    if ($ch -eq "q") { break }
    if ($ch -eq "w") { Write-Host "Mover: arriba" }
    if ($ch -eq "s") { Write-Host "Mover: abajo" }
    if ($ch -eq "a") { Write-Host "Mover: izquierda" }
    if ($ch -eq "d") { Write-Host "Mover: derecha" }
  }
}

